INSERT INTO `destinasi` (`id`, `kategori_id`, `nama_wisata`, `slug`, `deskripsi`, `alamat`, `jam_operasional`, `hari_operasional`, `harga_tiket`, `fasilitas`, `aturan`, `latitude`, `longitude`, `link_gmaps`, `thumbnail`, `created_at`, `updated_at`) VALUES
(1, 1, 'Air Terjun Batu Putu', 'air-terjun-batu-putu', 'Tahun Berdiri: Data tidak tersedia\n\nAir Terjun Batu Putu merupakan salah satu destinasi wisata alam yang berada di kawasan perbukitan Batu Putu, Kota Bandar Lampung. Kawasan ini awalnya dikenal oleh masyarakat sekitar sebagai sumber mata air alami yang dimanfaatkan untuk kebutuhan sehari-hari. Keindahan air terjun yang berada di tengah kawasan hutan dan perbukitan kemudian menarik minat masyarakat untuk berkunjung. Seiring waktu, Air Terjun Batu Putu berkembang menjadi salah satu objek wisata alam yang menawarkan suasana sejuk, pemandangan alam yang asri, serta aktivitas trekking ringan bagi wisatawan.', 'Sukadana Ham, Kecamatan Tanjung Karang Barat', '24 Jam', 'Setiap Hari', 0, '[2,3,4,5,7,8,10,11]', '1. Menjaga kebersihan kawasan wisata.\n2. Tidak membuang sampah sembarangan.\n3. Tidak merusak vegetasi atau fasilitas yang tersedia.\n4. Berhati-hati saat melewati jalur trekking yang licin.\n5. Tidak melakukan tindakan yang membahayakan diri sendiri maupun pengunjung lain.', '-5.4272834', '105.2182887', 'https://maps.app.goo.gl/NTxaCg8nCtbfuaUb9', '1782551060_11773245196a3f92143c4638.67824522.jpg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(2, 1, 'Taman Wisata Hutan Kera', 'taman-wisata-hutan-kera', 'Tahun Berdiri: 1995\n\nTaman Wisata Hutan Kera merupakan kawasan wisata fauna yang dikenal sebagai habitat kera ekor panjang (Macaca fascicularis). Menurut Ketua Pokdarwis, keberadaan kera di kawasan tersebut bermula ketika beberapa warga melepaskan kera peliharaan pada awal tahun 1990-an. Seiring waktu populasi kera berkembang hingga mencapai ratusan ekor. Kawasan ini juga memiliki nilai sejarah karena terdapat goa peninggalan Jepang dan bunker peninggalan masa kolonial Belanda.', 'Jl. Dr. Cipto Mangunkusumo Kelurahan Sumur Batu', '24 Jam', 'Setiap Hari', 0, '[3,12,14,15]', '1. Menjaga kebersihan kawasan wisata.\n2. Tidak membuang sampah sembarangan.\n3. Tidak mengganggu atau menyakiti kera.\n4. Tidak memberi makanan berbahaya kepada satwa.\n5. Berhati-hati saat berinteraksi dengan kera.\n6. Menjaga ketertiban dan keamanan selama berada di lokasi wisata.', '-5.4336517', '105.2693532', 'https://maps.app.goo.gl/AMFZr8efwHjGa7BM7', '1782551060_20352726746a3f921446f927.39438711.jpg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(3, 1, 'Sumur Putri', 'sumur-putri', 'Tahun Berdiri: 2015 (Tahun pembentukan Desa Wisata Sumur Putri)\n\nMenurut legenda yang berkembang di masyarakat Lampung, Sumur Putri berkaitan dengan kisah cinta antara seorang putri dari keluarga bangsawan dan seorang pemuda sederhana. Hubungan mereka tidak mendapat restu sehingga keduanya harus berpisah. Kesedihan yang dialami sang putri membuatnya sering menangis di sebuah taman. Masyarakat setempat meyakini bahwa air mata sang putri kemudian membentuk sebuah sumur yang kini dikenal sebagai Sumur Putri. Hingga saat ini, sumber air tersebut tetap mengalir dan tidak pernah mengering meskipun pada musim kemarau.\n\n(Sumber Sejarah: Papan Informasi Wisata Sumur Putri, Dinas Pariwisata Kota Bandar Lampung)', 'Sumur Putri, Kecamatan Teluk Betung Utara', '24 Jam', '', 0, '[2,5,6,7,11]', '1. Menjaga kebersihan kawasan wisata.\n2. Tidak membuang sampah sembarangan.\n3. Menjaga fasilitas yang tersedia.\n4. Tidak melakukan tindakan yang merusak lingkungan.\n5. Menjaga ketertiban dan keamanan selama berkunjung.\n6. Menghormati nilai budaya dan tradisi masyarakat setempat.', '-5.4393675', '105.2460603', 'https://maps.app.goo.gl/AD4uJQ5ex8LRPguz5', '1782551060_8097090106a3f92146a38d5.39592809.jpg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(4, 1, 'Kapal De Brow', 'kapal-de-brow', 'Tahun Berdiri: 1883 (Peristiwa Sejarah)\n\nBerdasarkan hasil wawancara dengan warga setempat, kawasan Sumur Putri memiliki keterkaitan dengan keberadaan sebuah kapal yang dikenal dengan nama Kapal De Brow. Kapal tersebut diceritakan sebagai kapal peninggalan masa kolonial Belanda yang keberadaannya dikaitkan dengan peristiwa letusan Gunung Krakatau tahun 1883. Menurut cerita yang berkembang di masyarakat, gelombang tsunami akibat letusan tersebut menyebabkan kapal terdampar di wilayah pesisir Teluk Betung. Seiring berjalannya waktu, kisah mengenai Kapal De Brow terus diwariskan dari generasi ke generasi dan menjadi bagian dari sejarah lokal Kota Bandar Lampung. Selain memiliki nilai sejarah, cerita mengenai kapal tersebut juga menjadi daya tarik bagi wisatawan yang ingin mengetahui jejak peristiwa letusan Krakatau di wilayah Lampung. Hingga saat ini, informasi mengenai Kapal De Brow masih dilestarikan melalui cerita masyarakat setempat.', 'Sumur Putri, Kecamatan Teluk Betung Utara', '24 Jam', 'Setiap Hari', 0, '[3,5,7]', '1. Menjaga kebersihan kawasan wisata.\n2. Tidak merusak situs sejarah.\n3. Menjaga keamanan dan ketertiban selama berkunjung.\n4. Mematuhi aturan yang berlaku di kawasan wisata.', '-5.4382233', '105.2472433', 'https://maps.app.goo.gl/LaMgL4onYNZ7RkFo9', '1782551060_13953898496a3f92147ee287.79900380.jpg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(5, 1, 'Desa Wisata Sumber Agung', 'desa-wisata-sumber-agung', 'Tahun Berdiri: 2020\n\nDesa Wisata Sumber Agung merupakan destinasi wisata berbasis masyarakat yang berada di Kecamatan Kemiling, Kota Bandar Lampung. Pengembangan wisata di kawasan ini diawali dengan terbentuknya Kelompok Sadar Wisata (Pokdarwis) Sumber Agung pada tahun 2015 sebagai wadah masyarakat dalam mengelola dan mengembangkan potensi wisata desa. Sejak berdirinya Pokdarwis, masyarakat bersama pengelola mulai melakukan berbagai upaya pelestarian lingkungan dan pengembangan potensi wisata yang dimiliki Desa Sumber Agung. Kawasan ini dikenal memiliki kekayaan alam berupa perbukitan, hutan, serta jalur trekking yang menarik untuk kegiatan wisata alam. Pada tahun 2020, pengelola mulai mengembangkan wisata Jungle Trekking sebagai salah satu daya tarik utama bagi wisatawan. Jalur trekking tersebut menawarkan pengalaman menjelajahi kawasan hutan dan menikmati keindahan alam yang masih asri. Pada tahun yang sama, Desa Sumber Agung resmi ditetapkan sebagai Desa Wisata Sumber Agung. Penetapan tersebut menjadi langkah penting dalam pengembangan sektor pariwisata berbasis masyarakat di wilayah tersebut. Seiring berjalannya waktu, Desa Wisata Sumber Agung tidak hanya menawarkan wisata alam, tetapi juga berbagai aktivitas edukasi dan pemberdayaan masyarakat yang melibatkan warga setempat. Keberadaan desa wisata ini diharapkan dapat meningkatkan kesejahteraan masyarakat sekaligus menjaga kelestarian lingkungan.\nHingga saat ini, Desa Wisata Sumber Agung terus berkembang sebagai salah satu destinasi wisata alam dan edukasi di Kota Bandar Lampung yang mengedepankan konsep wisata berkelanjutan dan partisipasi masyarakat.', 'Jalan Wan Abdurrahman Sumber Agung (Depan Wisata Lengkung Langit )', '24 Jam', 'Setiap Hari', 120000, '[8,27,28,39]', 'Mengikuti arahan pengelola saat mengikuti kegiatan wisata', '-5.417715', '105.1865139', 'https://maps.app.goo.gl/iVyHrai2xNr7uNE47', '1782551060_20753709666a3f9214953be5.63887429.jpg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(6, 1, 'Paintball Lampung', 'paintball-lampung', 'Tahun Berdiri: 2002\n\nHutan Pinus Lapangan Tembak Lampung merupakan kawasan wisata alam yang awalnya digunakan sebagai area pribadi dan belum dikelola sebagai destinasi wisata umum. Kawasan ini berada di lingkungan hutan pinus yang memiliki suasana sejuk dan pemandangan alam yang asri sehingga sering dimanfaatkan untuk berbagai kegiatan luar ruangan. Seiring berjalannya waktu, lokasi tersebut mulai dikenal oleh masyarakat, khususnya kalangan pelajar dan mahasiswa. Banyak siswa SMA serta mahasiswa yang datang untuk melaksanakan kegiatan kebersamaan, seperti malam keakraban (makrab), studi lapangan, dan kegiatan organisasi lainnya. Meningkatnya jumlah pengunjung yang memanfaatkan kawasan tersebut untuk kegiatan kelompok mendorong pengelola untuk mulai mengembangkan fasilitas yang lebih terarah. Pengembangan dilakukan agar kegiatan yang berlangsung dapat berjalan dengan lebih nyaman dan terorganisir. Melihat potensi wisata alam yang dimiliki kawasan tersebut, pengelola kemudian mulai menyediakan area khusus untuk kegiatan berkemah. Kawasan ini selanjutnya berkembang menjadi lokasi camping ground yang dapat digunakan oleh berbagai kelompok dan komunitas. Selain camping ground, pengelola juga mengembangkan berbagai aktivitas luar ruangan yang mendukung kegiatan edukasi, rekreasi, dan pelatihan kelompok. Salah satu aktivitas yang kemudian diperkenalkan adalah permainan paintball yang menjadi daya tarik bagi pengunjung. Pengembangan fasilitas dilakukan secara bertahap dengan tetap mempertahankan kondisi alam yang ada. Keberadaan pepohonan pinus yang mendominasi kawasan menjadi salah satu daya tarik utama bagi wisatawan yang ingin menikmati suasana alam terbuka. Kawasan ini juga mulai dimanfaatkan sebagai lokasi kegiatan outbound dan pelatihan kelompok. Berbagai instansi, sekolah, kampus, maupun organisasi memanfaatkan area tersebut untuk kegiatan pengembangan kerja sama tim dan kepemimpinan. Dengan bertambahnya fasilitas dan aktivitas yang tersedia, Hutan Pinus Lapangan Tembak semakin dikenal sebagai tempat wisata berbasis alam dan petualangan di Kota Bandar Lampung. Lokasi ini menawarkan pengalaman wisata yang berbeda dibandingkan destinasi rekreasi perkotaan. Pengelola terus berupaya menjaga kelestarian lingkungan hutan sebagai bagian penting dari daya tarik wisata. Konsep wisata yang dikembangkan mengedepankan kegiatan positif, edukatif, dan kebersamaan dalam suasana alam terbuka. Hingga saat ini, Hutan Pinus Lapangan Tembak tetap beroperasi sebagai kawasan wisata alam yang menyediakan fasilitas camping ground, outbound, dan paintball, serta menjadi lokasi berbagai kegiatan sekolah, kampus, instansi, dan komunitas.', 'JL RADEN IMBA KUSUMA RATU (Hutan Pinus Lapangan Tembak Lampung )', '24 Jam (sesuai jadwal kegiatan dan reservasi)', 'Setiap Hari', 3500000, '[2,3,28,29,30,32,33,34]', '1. Kawasan wisata diperuntukkan bagi kegiatan sekolah, kampus, instansi, komunitas, dan organisasi.\n2. Tidak menerima pengunjung yang datang untuk kegiatan berpacaran.\n3. Turut menjaga kelestarian kawasan hutan pinus.', '-5.4267056', '105.2304655', 'https://maps.app.goo.gl/BftdFbqK2UjGbCd69', '1782551060_21062171506a3f92149a64b3.51010782.jpg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(7, 1, 'Wira Garden', 'wira-garden', 'Tahun Berdiri: 2007\n\nTaman Wisata Wira Garden terletak di Kelurahan Batu Putuk Kecamatan Teluk Betung Barat, Kota Bandar Lampung. Taman wisata ini menempati areal seluas ±13 Ha. Taman wisata ini dibuka sebagai objek wisata alam untuk pertama kali tahun 2007 oleh Bapak Tri Wibowo sebagai pemilik Taman Wisata Wira Garden. Jarak tempuh Taman Wisata Alam Wira Garden ini dari pusat kota Bandar Lampung 7 km atau sekitar 30 menit dengan menggunakan kendaraan sepeda motor. Sektor pariwisata menjadi salah satu harapan pertumbuhan ekonomi di Kota Bandar Lampung, dan Taman Wisata Wira Garden merupakan salah satu kekayaan alam yang dijadikan objek wisata daerah.\n\n(Sumber sejarah: Astuti, B.T. 2015. Penilaian Potensi Taman Wisata Wira Garden Kelurahan Batu Putuk Kecamatan Teluk Betung Barat Kota Bandar Lampung Tahun 2014. Skripsi. Universitas Lampung. digilib.unila.ac.id)', 'JL. Wan Abdurrahman Batu Putu, Kecamatan Teluk Betung Utara', 'Senin - Jum\'at= 09.00 - 17.00 WIB', 'Setiap Hari', 15000, '[1,2,3,4,5,6,34,55]', '1. Dilarang membuang sampah atau apapun yang dapat mengotori dan berpotensi mencemari sungai\n2. Orang tua/pendamping wajib selalu mengawasi anak/siswa yang sedang berkegiatan di sungai\n3. Alas kaki wajib di pakai selama berkegiatan di area sungai\n4. Dilarang melompat ke dalam air atau berlompatan diatas batu di area sungai\n5. Dilarang berenang/bermain di area sungai yang dalam bermainlah di area sungai dangkal dan berbatu\n6. Bila cuaca hujan berpotensi hujan, wisatawan dilarang berkegiatan di sungai dan sepadan sungai karena berpotensi air deras dari hulu sungai\n7. Pilihlah tempat yang aman dan mudah dalam evakuasi untuk berkegiatan di sungai\n8. Area sungai tidak di awasi oleh lifeguard/penjaga sehingga wisatawan di himbau untuk memperhatikan rambu peringatan keselamatan sungai dan aturan yang ada\n9. Saling mengingatkan sesama pengunjung tentang keamanan dan kebersihan demi kenyamanan dan keselamatan bersama\n10. Menjaga barang &amp; kendaraan yg dibawa, kerusakan &amp; kehilangan di luar tanggung jawab Manajemen', '-5.4353007', '105.2296497', 'https://maps.app.goo.gl/LDKSRRCcQhAGwHhq6', '1782551060_3301741116a3f9214af1da9.71906246.jpg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(8, 1, 'Way Betoeng', 'way-betoeng', 'Tahun Berdiri: 2024\n\nBerdasarkan keterangan pemilik wisata Way Betoeng. Awalnya, beliau ingin memiliki sebuah tempat yang bisa digunakan untuk outbound, camping, dan berkumpul bersama banyak orang tanpa harus berdesakan dengan pengunjung lain. beliau juga ingin menciptakan tempat yang aman, nyaman, dan membuat setiap kegiatan bisa berjalan dengan lebih leluasa.\n\nDari keinginan itulah Way Betoeng mulai dibangun. Konsep yang dipilih adalah wisata privat, sehingga setiap kelompok yang datang dapat menikmati kegiatan mereka dengan lebih tenang tanpa terganggu keramaian. Percaya bahwa kenyamanan, keamanan, dan kebersamaan adalah hal yang penting dalam setiap kegiatan, baik itu untuk belajar, bermain, maupun sekadar menikmati alam.\n\nSeiring waktu, Way Betoeng mulai dipercaya oleh berbagai kalangan. Mulai dari mahasiswa, sekolah tingkat SD hingga SMA, pondok pesantren, komunitas, hingga berbagai instansi untuk mengadakan kegiatan outbound, camping, gathering, dan acara lainnya.\n\nSampai hari ini, Way Betoeng terus berkembang dengan tetap membawa tujuan yang sama seperti saat pertama kali dibangun yaitu menyediakan tempat yang nyaman untuk berkumpul, belajar, dan menikmati suasana alam.', 'Batu Putuk, Kec. Tlk. Betung Utara, Kota Bandar Lampung, Lampung', '08.00 – 18.00 WIB (Paket Outbound).', 'Setiap hari (dengan sistem reservasi/janji temu terlebih dahulu)', 0, '[2,8,28,30,34,39,44,55]', '1. Kunjungan dilakukan melalui reservasi atau janji temu terlebih dahulu.\n2. Penyewaan berlaku untuk satu kawasan wisata, bukan per orang.\n3. Check-out kegiatan camping maksimal pukul 08.00 WIB.\n4. Keterlambatan check-out akan dihitung sebagai paket outbound hari berikutnya.\n5. Menjaga kebersihan dan kelestarian kawasan wisata.\n6. Menjaga fasilitas yang tersedia dan tidak merusaknya.\n7. Mematuhi arahan pengelola selama kegiatan berlangsung.', '-5.4461367', '105.2147', 'https://maps.app.goo.gl/jnvxCghA49qwi5Hk6', '1782551060_16561234516a3f9214d6aeb8.51705726.png', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(9, 2, 'Bukit Sakura', 'bukit-sakura', 'Tahun Berdiri: 2018\n\nBukit Sakura secara resmi berdiri sebagai tempat wisata pada tahun 2018. Namun sebenarnya bangunan utamanya sudah mulai didirikan sejak sekitar tahun 2016. Jadi ada jarak 2 tahun antara pembangunan fisik dengan peresmian sebagai destinasi wisata. Awalnya Bukit Sakura tidak dirancang untuk menjadi tempat wisata. Konsep awalnya adalah vila pribadi. Tempat ini dibangun sebagai tempat beristirahat yang tenang dengan pemandangan perbukitan khas Kemiling, Bandar Lampung. Seiring berjalannya pembangunan, keberadaan vila ini mulai menarik perhatian. Banyak warga sekitar maupun warga dari luar Kecamatan Kemiling yang penasaran dan datang berkunjung ke lokasi. Mereka tertarik dengan suasana bukit dan desain bangunan yang berbeda dari tempat lain.\n\nMelihat banyaknya warga yang datang, para pengunjung kemudian banyak memberikan saran. Mereka menyarankan agar tempat ini dibuka untuk umum dan dijadikan objek wisata. Usulan warga ini akhirnya ditanggapi oleh pemilik vila karena dinilai punya potensi yang bagus.  Dari masukan warga itulah, pada tahun 2018 Bukit Sakura resmi dibuka sebagai wisata. Nama &quot;Bukit Sakura&quot; sendiri diambil dari dua hal. Pertama, lokasi tempat ini memang berada di area perbukitan. Kedua, di wilayah sekitar banyak gang yang bertema Jepang seperti Tokyo dan Hiroshima. Karena nuansanya, dipilih nama &quot;Sakura&quot;. Saat ini Bukit Sakura mengusung tema Jepang, Korea, dan Belanda sebagai daya tarik utamanya.', 'Jl. Melati Raya, Langkapura, Kecamatan Langkapura, Kota Bandar Lampung', '08.00 - 17.00 WIB', 'Setiap Hari', 15000, '[1,2,3,4,5,6,45,46,47,48,49,51,52]', 'Mengawasi anak-anak saat menggunakan fasilitas bermain atau kolam renang', '-5.4042906', '105.2228136', 'https://maps.app.goo.gl/CURVFRExk7Ls9wH47', '1782551060_20276621916a3f9214df72d0.29292787.jpg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(10, 2, 'Kampoeng Vietnam', 'kampoeng-vietnam', 'Tahun Berdiri: Januari 2021\n\nKampoeng Vietnam merupakan salah satu destinasi wisata yang berada di kawasan Sumber Agung, Kecamatan Kemiling, Kota Bandar Lampung. Wisata ini dikenal karena berada di area perbukitan yang menawarkan panorama alam serta pemandangan Kota Bandar Lampung dari ketinggian. Nama &quot;Kampoeng Vietnam&quot; telah lama dikenal oleh masyarakat setempat sebagai sebutan untuk kawasan tersebut. Penamaan ini kemudian dipertahankan dan digunakan sebagai identitas destinasi wisata yang berkembang di wilayah tersebut. Keindahan alam yang dimiliki Kampoeng Vietnam menjadi salah satu faktor utama yang menarik wisatawan. Dari lokasi ini, pengunjung dapat menikmati suasana perbukitan yang sejuk serta pemandangan kota yang terlihat dari atas.\nSelain menawarkan panorama alam, Kampoeng Vietnam juga menjadi salah satu alternatif wisata keluarga dan wisata bersama teman. Lokasinya yang berada tidak jauh dari pusat Kota Bandar Lampung membuat destinasi ini cukup mudah dijangkau oleh pengunjung. Hingga saat ini, Kampoeng Vietnam masih menjadi salah satu destinasi wisata yang dikenal masyarakat Kota Bandar Lampung dan sekitarnya.\n\n(Sumber Sejarah: Jumanto.net (2023), Cantiknya Kampung Vietnam di Kemiling Bandar Lampung.)', 'Jl. Wan Abdurrahman, Sumber Agung, Kec. Kemiling, Kota Bandar Lampung, Lampung 35156', '07.00 - 22.00 WIB', 'Setiap Hari', 10000, '[1,5,6,55,56,57,58]', '1. Harga tiket bisa naik pada saat event tertentu \n2. Anak kecil di atas 3-5 tahun sudah dihitung tiketnya\n3. Jaga kebersihan &amp; kelestarian', '-5.4157651', '105.193383', 'https://maps.app.goo.gl/XKzmmvsvE5afqKHYA', '1782551060_2205441676a3f9214e63d23.64791844.jpg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(11, 2, 'Waterpark Bumi Kedaton', 'waterpark-bumi-kedaton', 'Tahun Berdiri: 2004\n\nWaterpark Bumi Kedaton merupakan bagian dari kawasan wisata Bumi Kedaton yang berada di Batu Putu, Kota Bandar Lampung. Kawasan wisata ini dibangun pada tahun 2004 di atas lahan bekas perkebunan durian dan dikembangkan sebagai destinasi rekreasi keluarga yang memanfaatkan keindahan alam perbukitan. Seiring perkembangannya, kawasan Bumi Kedaton dilengkapi berbagai fasilitas wisata, termasuk wahana permainan air yang kemudian dikenal sebagai Waterpark Bumi Kedaton. Keberadaan waterpark tersebut menjadikan Bumi Kedaton sebagai salah satu tujuan wisata keluarga yang cukup populer di Kota Bandar Lampung.\n\n(Sumber Sejarah: IDN Times Lampung (2023), Sempat Hype, Ini Kondisi Taman Bumi Kedaton Milik Eks Gubernur Lampung.)', 'Jln. Wan Abdurrahman Batu Putuk Teluk Betung', '08.00 - 17.00 WIB', 'Setiap Hari', 10000, '[2,4,6,34,48]', 'Diperbolehkan membawa makanan dari luar tempat wisata', '-5.4348766', '105.2262448', 'https://maps.app.goo.gl/NvEkuDDbdjb3H5DZ6', '1782551060_6527468816a3f9214f064a7.96344961.jpg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(12, 2, 'Kolam Renang Bukit Mas', 'kolam-renang-bukit-mas', 'Tahun Berdiri: 2016\n\nKolam Renang Bukit Mas merupakan salah satu destinasi rekreasi keluarga yang berada di kawasan perbukitan Sukadana Ham, Kota Bandar Lampung. Wisata ini dikembangkan sebagai bagian dari kawasan Bukit Mas Cottage &amp; Resto yang menawarkan fasilitas penginapan, restoran, serta kolam renang dengan pemandangan Kota Bandar Lampung dari ketinggian. Lokasinya yang berada di area perbukitan memberikan suasana sejuk dan panorama alam yang menjadi daya tarik utama bagi pengunjung.\nSelain sebagai tempat berenang, kawasan Bukit Mas juga dimanfaatkan sebagai lokasi bersantai dan menginap bagi wisatawan. Fasilitas yang tersedia terus berkembang untuk mendukung kebutuhan rekreasi keluarga maupun wisatawan yang ingin menikmati suasana alam Kota Bandar Lampung. Hingga saat ini, Kolam Renang Bukit Mas masih menjadi salah satu pilihan wisata rekreasi yang menawarkan kombinasi antara fasilitas kolam renang, penginapan, dan pemandangan alam.\n\n(Sumber Sejarah: Omnduut, &quot;Puncak Mas: Tempat Kreasi Cetar di Bandar Lampung&quot;, 2017.)', 'JL Raden Imba Kusuma Ratu No. 2A, Sukadana Ham, Kec. Tj. Karang Barat, Kota Bandar Lampung', '08.00 - 21.00 WIB', 'Setiap Hari', 40000, '[2,3,5,48,55]', 'Dilarang membawa makanan dari luar dan Wajib membeli tiket jika sudah memasuki area kolam bagi yang berenang/tidak.', '-5.416978', '105.2315867', 'https://maps.app.goo.gl/6h9gQMiFJGzGrHnEA', '1782551061_12346359696a3f9215095596.80757379.jpg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(13, 2, 'Puncak Mas Thomas', 'puncak-mas-thomas', 'Tahun Berdiri: 2017\n\nPuncak Mas Thomas merupakan destinasi wisata pegunungan yang mulai beroperasi pada tahun 2017. Data tahun berdiri tersebut diperoleh langsung dari pihak pengelola melalui komunikasi WhatsApp pada tanggal 12 Juni 2026. Wisata ini berlokasi di Jl. H. Hamim RJP, Sukadanaham, Tanjung Karang Barat, Kota Bandar Lampung.\n\nSejak awal berdirinya, Puncak Mas Thomas dikembangkan sebagai wisata alam yang menawarkan panorama Kota Bandar Lampung dari ketinggian. Dengan konsep wisata alam terbuka, destinasi ini menjadi alternatif rekreasi keluarga dan spot foto yang dapat diakses dari pusat kota. Hingga saat ini, Puncak Mas Thomas terus menjadi salah satu pilihan wisata di Bandar Lampung yang merupakan bagian dari Group of Tegal Mas Thomas, Bukit Mas Thomas, dan Kopi Tanow.', 'Jl. H. Hamim RJP, Sukadanaham, Tanjung Karang Barat, Kota Bandar Lampung, Lampung', '08.00 – 22.00 WIB', 'Setiap Hari', 20000, '[3,4,5,7,44,62]', 'Tidak membuang sampah sembarangan', '-5.4205854', '105.2276484', 'https://maps.app.goo.gl/2Fef9A4W1ZBFya2L6', '1782551061_13555703186a3f921513ef60.57587541.jpg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(14, 2, 'Farmora', 'farmora', 'Tahun Berdiri: 2024\n\nWisata Farmora merupakan destinasi edutainment farm yang mulai beroperasi pada tahun 2024. Informasi tahun berdiri tersebut diperoleh langsung dari pihak pengelola Farmora melalui komunikasi WhatsApp pada tanggal 17 Juni 2026. Farmora berlokasi di Jl. Khadin tihang, Gg. Pertama, No. 4, Kelurahan Sukarame II, Kecamatan Teluk Betung Barat, Kota Bandar Lampung. Farmora dikembangkan sebagai wisata alam yang menggabungkan unsur edukasi pertanian dan peternakan. \n\nKonsep Farmora adalah menghadirkan suasana pedesaan yang asri dan tenang di tengah kota. Begitu memasuki Farmora, pengunjung disambut hamparan tanaman rapi, suara hewan ternak, serta udara bersih yang menghadirkan sensasi pedesaan. Pengelola Farmora, Januar Jalu Anggoro, menyatakan bahwa wisata ini bukan sekadar tempat bersantai, tetapi juga menawarkan pengalaman edukatif agar pengunjung memahami proses pertanian dan peternakan secara langsung. \n\n(Sumber sejarah: \n1. Hasil komunikasi dengan Pengelola Farmora via WhatsApp, 17 Juni 2026\n2. publikasilampung.id, &quot;Farmora, Wisata Edukasi Asri Dekat Pusat Kota Bandarlampung&quot;)', 'Jl. Khadin Tihang, Gg. Pertama, No. 4,  Sukarame II, Kec. Teluk Betung Barat, Kota Bandar Lampung', 'Senin - Jumat: 09.00 - 17.00 WIB', 'Setiap Hari', 15000, '[5,7,48,64]', '1. Kolam renang dikenakan biaya tambahan Rp15.000 di luar tiket masuk\n2. Untuk paket wisata anak sekolah silakan tanya admin', '-5.4409919', '105.2149484', 'https://maps.app.goo.gl/SiNBs1s8hV5RcU31A', '1782551061_16174959376a3f9215195d86.54564775.jpg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(15, 3, 'Cikwo Kuliner Lampung', 'cikwo-kuliner-lampung', 'Tahun Berdiri: 2015\n\nPada masa kecil kita mungkin punya kenangan tentang satu makanan khas atau tradisional. Namun seiring perkembangan zaman beberapa makanan khas tersebut saat ini sulit ditemukan lagi. Hal ini karena sudah jarang yang membuat ataupun menjualnya. Berawal dari sinilah, rasa malu dan kegelisahan Ibu Isna Adianti yang sering menerima tamu dari luar daerah, dimana tamu-tamu tersebut banyak yang bertanya tentang restoran yang menyajikan makanan khas Lampung, dan pada saat itu (tahun 2015) sangat jarang bahkan belum ada restoran yang menyediakan masakan khas Lampung di Kota Bandar Lampung. Untuk itulah Cikwo Kuliner Khas Lampung hadir di Bandar Lampung sejak tahun 2015, bertujuan agar masyarakat kota Bandar Lampung maupun wisatawan dari luar kota bisa menikmati masakan asli tradisional khas Lampung.', 'Cikwo Kuliner Khas Lampung, (Kimaja Icon), samping Indomaret, 50m sebelum fly over, Jl. Ki Maja, Sepang Jaya, Labuhan Ratu, Bandar Lampung City, Lampung 35132', '10.00 – 22.00 WIB', 'Setiap Hari', 25, '[11]', 'Seruit, Gulai Taboh Iwa Tapa (ikan asap), Paket Pahar, Pandap, Pekhos Masin, Pekhos Pati', '-5.3736154', '105.2738756', 'https://maps.app.goo.gl/5HDpxdrZRajL6hqZ7', '1782551061_5224088186a3f9215208596.02210376.jpg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(16, 3, 'Rumah Makan Bubur Acung JR', 'rumah-makan-bubur-acung-jr', 'Tahun Berdiri: 1954\n\nBubur Ayam Acung JR adalah warisan kuliner legendaris Kota Bandar Lampung yang dirintis sejak tahun 1954 oleh pasangan Wong Lok dan Eng Xiu. Keduanya merupakan perantau generasi pertama asal Tiongkok yang hijrah ke Indonesia pada tahun 1930 untuk memperbaiki nasib di masa penjajahan Jepang.\n\nAwalnya, kakek dan nenek hanya berjualan bubur ayam keliling menggunakan gerobak kecil di wilayah Teluk Betung. Saat itu bubur ayam belum populer di Lampung, sehingga menjadi kuliner unik khas Tionghoa yang mereka bawa dari kampung halaman. Karena cita rasanya yang otentik, usaha ini terus berkembang.\n\nPada tahun 1970, usaha diteruskan oleh anaknya dan resmi menggunakan nama &quot;Bubur Ayam Acung&quot; yang diambil dari nama beliau. Gerobak kayu klasik dengan ciri khas tertentu menjadi identitas yang dipertahankan hingga sekarang. Tahun 1997, usaha ini mendapat penghargaan dari Wali Kota karena konsistensinya berjualan di Pasar Mambo, Teluk Betung sejak era 70-an.\n\nGenerasi ketiga, Teddy Wijaya, mulai melanjutkan usaha keluarga sejak 2012 dan membuka cabang di Jalan Antasari pada 2015. Hingga kini Bubur Ayam Acung JR tetap mempertahankan resep original dari kakek-nenek: bubur dengan kaldu ayam kental dan topping khas seperti cakwe serta tongcay. (Sumber: Video wawancara Bubur Ayam Acung JR dengan SEA Today News)', 'Jl. Pangeran Antasari No. 87, Bandar Lampung', '13.30 - 23.00 WIB', 'Setiap Hari', 20, '[2,3,11,71]', 'Bubur Ayam, Nasi Tim Ayam Kampung, Bubur Kacang Ijo, Bubur Jali-Jali', '-5.4076446', '105.273479', 'https://maps.app.goo.gl/Dzk3kc5rhuP2rF2K8', '1782551061_8985222046a3f92152e7d86.58532726.jpg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(17, 3, 'Pindang Pegagan Kei', 'pindang-pegagan-kei', 'Tahun Berdiri: 2018\n\nRumah Makan Pindang Pegagan Kei merupakan usaha kuliner yang berawal dari warisan keluarga. Pada tahun 2002–2006, orang tua pemilik pertama kali membuka usaha pindang di Jl. Cut Mutia, Teluk. Namun, karena faktor usia, usaha tersebut sempat berhenti sementara waktu. Pada tahun 2016, usaha kembali dirintis oleh generasi selanjutnya dengan membuka tempat di kawasan Prapatan Gunung Sulah. Seiring berjalannya waktu, karena tempat tersebut tidak lagi disewakan, usaha kemudian dipindahkan ke lokasi yang sekarang. Secara resmi, Rumah Makan Pindang Pegagan Kei mulai beroperasi di tempat saat ini sejak tahun 2018 dan hingga kini.', 'Jl. Gatot Subroto No.173, Sukaraja, Kec. Telukbetung Selatan, Kota Bandar Lampung, Lampung', '10.00 - 16.00 WIB', 'Setiap Hari', 30, 'Harga sudah include dengan lalapan prasmanan', 'Pindang patin, pindang baung, pindang kepala simba, pepes patin, pepes baung, ayam goreng, nila goreng, dan tahu tempe', '-5.4427515', '105.291865', 'https://maps.app.goo.gl/fGFYEZEX1qkM7xiW9', '1782551061_18573702406a3f92153d5010.51123912.jpg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(18, 3, 'Restoran Garuda', 'restoran-garuda', 'Tahun Berdiri: 1988\n\nRestoran Garuda merupakan rumah makan khas Minang dan Melayu yang pertama kali berdiri pada tahun 1976 di Medan. Pendirian restoran ini berawal dari hasil survei yang menunjukkan masih kurangnya rumah makan yang menyajikan masakan khas Minang dan Melayu di kota Medan pada saat itu.\n\nSeiring perkembangan usaha, Restoran Garuda membuka cabang di beberapa kota besar di Indonesia, termasuk Jakarta, Pekanbaru, dan Bandar Lampung. Cabang Bandar Lampung berlokasi di Jl. Cut Nyak Dien No. 20-24, Palapa, Tanjung Karang Pusat. \n\nRestoran Garuda berdiri sejak tahun 1972¹ dan dikenal sebagai restoran Padang legendaris di Lampung².\n\n¹ Sumber: Website resmi Restoran Garuda, restorangaruda.com  \n² Sumber: Artikel &quot;10 tempat makan enak di Lampung&quot;, Pergimulu.com', 'Jl. Cut Nyak Dien No. 24-20, Bandar Lampung', '07.00 - 22.00 WIB', 'Setiap Hari', 25, '[3,11,75,76]', 'Kepala kakap, barendo, dan ayam goreng', '-5.4188732', '105.252751', 'https://maps.app.goo.gl/Ne6rLCCDz9hC6TEYA', '1782551061_855367556a3f921546ad83.25411544.jpg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(19, 3, 'Pempek NORI', 'pempek-nori', 'Tahun Berdiri: 2010\n\nPempek Nori berdiri pada tahun 2010 di Teluk Betung Kota Bandar Lampung. Nama Pempek Nori diambil dari nama pemilik usaha tersebut. Pemilik usaha adalah Ibu Nori.', 'Jl. Ikan Kakap No. 46, Teluk Betung, Bandar Lampung', '07.00 - 17.00 WIB', 'Selasa - Minggu', 6, '[2,3,11]', 'Pempek isi keju', '-5.4491413', '105.2636762', 'https://maps.app.goo.gl/GbKQwshUm1MrQfo88', '1782551061_20845318866a3f921552f956.38100288.jpg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(20, 3, 'Taman Santap Rumah Kayu', 'taman-santap-rumah-kayu', 'Tahun Berdiri: 20 des 2006\n\nTaman Santap Rumah Kayu mengusung konsep makan keluarga yang dipadukan dengan suasana alam. Restoran ini menyediakan menu seafood segar dengan cita rasa autentik, serta memiliki bangunan kayu yang memberi kesan tradisional dan elegan. Lokasinya yang luas menjadikan tempat ini sesuai untuk acara keluarga besar. Selain itu, area taman hijau yang asri dan fasilitas bermain anak membuat pengunjung merasa nyaman, sehingga banyak yang kembali untuk menikmati pengalaman bersantap di tempat ini. \n\n(Sumber: Kementerian Pariwisata dan Ekonomi Kreatif. Indonesia.travel. Diakses 08 Mei 2026.)', 'Jl. Arif Rahman Hakim No.45, Wayhalim, Bandar Lampung', '10.00 - 21.00 WIB', 'Setiap Hari', 50, '[4,64,84]', 'ayam Kalasan, ikan simba bakar dabu-dabu, gurame bakar RK, es durian, green fresh, es campur RK', '-5.3935947', '105.2814296', 'https://maps.app.goo.gl/ZfkxQvdMVBygs3ui6', '1782551061_20513897786a3f921560a2c8.16041750.jpg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(21, 3, 'Pempek Tenda Biru Rajabasa', 'pempek-tenda-biru-rajabasa', 'Tahun Berdiri: 2011\n\nPada tahun 1980 awal pendirian Pempek Tenda Biru bermula dari keahlian khusus Ibu Maryam dalam pembuatan pempek. Pada awalnya, Ibu Maryam belum memiliki tempat untuk berjualan, sehingga pempek hasil produksi dijual oleh pedagang lain. Pedagang-pedagang ini menjajakan dagangan dengan menggunakan keranjang dan berjalan kaki di sekitar kota Palembang. Pada 1992 warung pertama seiring berjalannya waktu, Ayah Kemas H. Muhammad Yunus dan Ibu Maryam membuka warung pertamanya di depan kampus Tridinanti Palembang. Untuk memberikan pengenalan yang lebih mudah terhadap usaha mereka, para pelanggan memberi nama &quot;Pempek Tenda Biru.&quot; Nama ini terinspirasi dari penggunaan terpal berwarna biru yang menjadi ciri khas dari warung mereka. Terpal biru tersebut kemudian melekat dan menjadi bagian dari identitas Pempek Tenda Biru.\n\nTahun 2002 pindah ke Bandar Lampung, Ayah Kemas H. Muhammad Yunus dan Ibu Maryam memutuskan untuk pindah ke Bandar Lampung. Mereka membuka warung pertama di dekat perlintasan rel kereta api di JI. Urip Sumoharjo dengan nama yang sama, &quot;Pempek Tenda Biru&quot;. Meskipun berpindah kota, identitas dan nama usaha tetap dipertahankan. Ayah Kemas H. Muhammad Yunus membangun ruko pertama di Jl. Kimaja, depan SPBU Way Halim Permai. Tempat ini menyediakan parkir yang luas dan juga menyediakan area makan VIP Room, sehingga cocok bagi rombongan dalam jumlah besar dan yang ingin mengadakan berbagai macam acara di tahun 2005.\n\nPembukaan ruko kedua pada tahun 2008, Pempek Tenda Biru mengembangkan usaha dengan membuka ruko kedua di Jl. Zainal Abidin Pagar Alam. Keputusan ini didasari oleh semakin meningkatnya jumlah pengunjung. Selain itu, lokasinya searah dengan jalan menuju ke luar kota dan bandara, sangat memudahkan pembeli yang akan bepergian ke luar kota. Perluasan usaha terus berlanjut pada tahun 2011 dengan pembukaan ruko ketiga di Jl. Tamin, depan Masjid Falahuddin. Lokasinya dekat dengan daerah perhotelan dan menjadi pilihan yang sangat cocok bagi wisatawan yang baru selesal berwisata di pantal ataupun lokasi wisata Lampung lainnya.', 'Jl. ZA. Pagar Alam No.57, Gedong Meneng, Kec. Rajabasa, Kota Bandar Lampung, Lampung 35145', '07.00 - 21.00 WIB', 'Setiap Hari', 6, '[3]', 'Pempek Kapal Selam', '-5.375201', '105.2436547', 'https://maps.app.goo.gl/kr1mGRDEvKfb1xBM7', '1782551061_11567256746a3f92156a1482.45579787.jpg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(22, 3, 'Restoran Ayam Bebek Haji Soleh Pahoman', 'restoran-ayam-bebek-haji-soleh-pahoman', 'Tahun Berdiri: 2021\n\nBerawal dari warung tenda sederhana di sudut kota Bandar Lampung tahun 1980-an, Restoran Ayam Bebek Haji Soleh lahir dari resep ayam goreng warisan keluarga. Dengan prinsip: bahan berkualitas, resep otentik, dan pelayanan ramah seperti keluarga sendiri, warung kecil itu pelan-pelan dipercaya pelanggan. Dari tenda, naik jadi ruko permanen, lalu buka cabang biar makin banyak yang bisa nikmatin. Sampai sekarang, kami tetap pegang nilai yang sama. Haji Soleh nggak cuma jual ayam bebek goreng, tapi juga ngumpulin cerita. Di sini, dari kakek-nenek sampai anak muda, semua bisa ketemu sambil makan &quot;masakan rumah&quot; yang bikin kangen. Terima kasih udah jadi bagian dari perjalanan panjang kami (Sumber: Blog resmi Restoran Ayam Bebek Haji Soleh, 5 Januari 2025.)', 'JL Ir. H. Juanda Pahoman, Samping flyover Pahoman, Pahoman, Bandar Lampung', '09.00 - 21.00 WIB', 'Setiap Hari', 5, '[3,4]', 'Ayam bakar, bebek bakar, pindang patin, nila bakar', '-5.4239043', '105.2696532', 'https://maps.app.goo.gl/YwJ7ACi6ffThJuEV8', '1782551061_2313787856a3f921575f225.65098608.jpg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(23, 3, 'D\'Rajash Resto', 'd-rajash-resto', 'Tahun Berdiri: 2024\r\n\r\nD\'Rajash Resto yang berlokasi di Jl. Teuku Umar, Kedaton (Komplek PTPN 7), Bandar Lampung, dibangun sebagai restoran berkonsep aesthetic yang menyajikan hidangan Nusantara (seperti paket ayam, pindang baung, dan seruit) serta menu Western.\r\nRestoran ini didirikan sebagai destinasi kuliner dengan area bersantap yang nyaman, luas, dan estetik, sehingga juga populer digunakan sebagai lokasi intimate wedding.', 'Jl. Teuku Umar, Kedaton, Kec. Kedaton, Kota Bandar Lampung, Lampung, Indonesia', '10.00 - 22.00 WIB', 'Setiap Hari', 25, '1. Akses Pembayaran Non-Tunai\n   Melayani pembayaran melalui kartu kredit, kartu debit, serta dompet digital/QRIS untuk kemudahan transaksi.\n2. Layanan Pemesanan &amp; Pengantaran\n   Tersedia layanan reservasi tempat untuk acara pribadi maupun korporat. Layanan delivery order juga tersedia melalui mitra aplikasi pemesanan makanan.\n3. Aksesibilitas &amp; Kenyamanan\n   Restoran dilengkapi akses ramah disabilitas/kursi roda dan area tempat duduk indoor maupun outdoor yang dirancang nyaman untuk keluarga, rombongan maupun pertemuan bisnis.\n4. Fasilitas Penunjang\n   Tersedia area parkir yang memadai, koneksi WiFi gratis, mushola, serta toilet bersih', 'Seafood Tumpah, Pindang Baung, dan Seruit', '-5.3848961', '105.2610975', 'https://maps.app.goo.gl/TCMX9241QoMKPrWE9', '1782551467_4605cb8ab3bba9aff52c.jpg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(24, 3, 'Kepiting Nyablak', 'kepiting-nyablak', 'Tahun Berdiri: 2018\n\nKepiting Nyablak merupakan salah satu usaha kuliner di Kota Bandar Lampung yang dikenal dengan sajian seafood bercita rasa pedas khas. Berdasarkan hasil wawancara dengan pihak admin, usaha ini berawal dari keinginan untuk menciptakan saus pedas original yang memiliki cita rasa berbeda dari produk sejenis yang sudah ada di pasaran. Ide tersebut kemudian diwujudkan melalui berbagai percobaan dan pengembangan resep hingga menghasilkan saus khas yang menjadi identitas utama Kepiting Nyablak. Saus tersebut dirancang untuk memberikan sensasi pedas yang unik namun tetap dapat dinikmati oleh berbagai kalangan pecinta kuliner. Seiring berjalannya waktu, menu seafood yang dipadukan dengan saus khas tersebut mulai mendapat perhatian dan respon positif dari masyarakat. Cita rasa yang khas menjadi salah satu alasan banyak pelanggan tertarik untuk mencoba dan kembali berkunjung.\nTidak hanya menawarkan kepiting sebagai menu utama, Kepiting Nyablak juga mengembangkan berbagai pilihan menu seafood lainnya untuk memenuhi kebutuhan dan selera pelanggan yang beragam. Inovasi menu terus dilakukan guna menjaga kualitas dan daya tarik usaha kuliner tersebut.\nSelain mengutamakan cita rasa, Kepiting Nyablak juga berusaha memberikan pelayanan yang baik dan suasana makan yang nyaman bagi pengunjung. Hal ini dilakukan untuk menciptakan pengalaman bersantap yang menyenangkan bagi setiap pelanggan. Hingga saat ini, Kepiting Nyablak terus berkembang sebagai salah satu destinasi kuliner di Kota Bandar Lampung. Keberadaan saus pedas original yang menjadi ciri khas usaha ini tetap dipertahankan sebagai identitas utama yang membedakannya dari kuliner seafood lainnya.', 'Jl. Pagar Alam Gang Lambang (PU) Kel. Labuhan Ratu, Bandar Lampung', '10.00 - 21.00 WIB', 'Setiap Hari', 25, '[2,3,11]', 'Kepiting Saus Nyablak dan Nasi Jukut', '-5.3842544', '105.2526975', 'https://maps.app.goo.gl/HFYHnSJsabCFHR217', '1782551061_10576378926a3f92157fd325.31712107.jpg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(25, 4, 'Pantai Tiska', 'pantai-tiska', 'Tahun Berdiri: 2020\n\nAwalnya kawasan ini merupakan pelabuhan yang berada di bawah pengelolaan PT KAI. Di tengah pelabuhan terdapat dermaga yang menjadi tempat berlabuhnya kapal-kapal sebelum pelabuhan resmi di Lampung Selatan dibangun. Seiring waktu, aktivitas pelabuhan kemudian dipindahkan ke Lampung Selatan. Kawasan bekas pelabuhan ini akhirnya dikembangkan menjadi Pantai Tiska sebagai destinasi wisata.', 'Srengsem, Kec. Panjang, Kota Bandar Lampung, Lampung', '07.00 - 22.00 WIB', 'Setiap Hari', 20000, '[1,2,5,7,55]', 'Berhati-hati di sekitar pantai, anak-anak yang berenang wajib dalam pengawasan orang tua, dan buang sampah pada tempatnya', '-5.4918777', '105.3255907', 'https://maps.app.goo.gl/LdVZx7AKB8tjtHKn9', '1782551061_13599756676a3f92158aefe6.82653788.jpg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(26, 4, 'Pantai Indah Gunung Kunyit', 'pantai-indah-gunung-kunyit', 'Tahun Berdiri: Mulai berkembang sejak proses reklamasi tahun 2013–2016\n\nPantai Indah Gunung Kunyit merupakan kawasan pantai di dekat Gunung Kunyit Bandar Lampung. Pantai yang terbentuk dari endapan tanah hasil reklamasi pantai tahun 2013 sampai 2016. Pantai ini memiliki karakteristik yang berbeda karena pinggirnya terdapat bebatuan semua. Seiring berjalannya waktu masyarakat sekitar mulai berpartisipasi dengan membuka usaha kuliner seperti warung kopi, seblak, dan pop mie. Selain itu, terdapat pula pedagang keliling yang menggunakan kendaraan roda dua untuk berjualan di area pantai. Hal ini turut mendukung perekonomian warga lokal. Saat ini, pengelolaan Pantai Gunung Kunyit berada di bawah PT Teluk Wisata Lampung dengan nama &quot;Pantai Indah Gunung Kunyit&quot;.', 'Jl. Ikan Terbang, Bumi Waras, Kec. Telukbetung Selatan', 'Pagi dan Sore', 'Setiap Hari', 10000, '[5,11,102,103]', 'Buang sampah pada tempatnya dan berhati-hati karena dekat pelabuhan &amp; lalu lalang kapal', '-5.4471325', '105.2827167', 'https://maps.app.goo.gl/8dfZ93t2KhFPupnz7', '1782551061_10187403336a3f9215912ca9.62111631.jpg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(27, 4, 'Pantai Puri Gading', 'pantai-puri-gading', 'Tahun Berdiri: Data belum tersedia\n\nPantai Purigading merupakan bagian dari kawasan Perumahan Puri Gading di Kota Bandar Lampung. Kawasan ini pada awalnya dikembangkan sebagai area perumahan dengan konsep hunian tepi pantai. Salah satu karakteristik unik Pantai Puri Gading adalah ketersediaan lapangan terbuka dengan area yang luas. Lapangan tersebut pernah dimanfaatkan untuk kegiatan berskala internasional, yaitu simulasi penanggulangan bencana tsunami yang melibatkan dua negara, Indonesia dan Malaysia. Hal ini menunjukkan kapasitas area pantai yang memadai untuk kegiatan berskala besar.\n\nSelain kegiatan resmi, Pantai Puri Gading juga mulai dimanfaatkan sebagai lokasi resepsi pernikahan. Pemandangan laut dan sunset menjadi daya tarik utama bagi pasangan yang menginginkan konsep pernikahan outdoor. Untuk mendukung kebutuhan tersebut, pengelola menyediakan fasilitas gazebo dan gubuk yang dapat disewa oleh pengunjung. Pengembangan fasilitas wisata terus dilakukan untuk menarik minat pengunjung dari berbagai kalangan. Tersedia lapangan tenis, area pemancingan di ujung dermaga tempat bersandarnya kapal, area perkemahan di lapangan luas, serta penyediaan net untuk permainan voli. Keberagaman fasilitas ini menjadikan pantai tidak hanya sebagai tempat rekreasi, tetapi juga aktivitas olahraga dan edukasi. Meskipun memiliki potensi wisata yang cukup baik, pengelola mengakui bahwa akses jalan menuju lokasi masih belum optimal. Kondisi jalan yang berlubang menjadi kendala utama, terutama bagi pengunjung yang menggunakan kendaraan dengan jarak pijak rendah. Perbaikan infrastruktur jalan menjadi salah satu fokus pengelola ke depan agar aksesibilitas pantai semakin meningkat.', 'Jl. Laksamana R.E.Martadinata, Sukamaju, Teluk Betung Barat, Bandar Lampung', '09.00 - 17.00 WIB', 'Senin - Jumat: 07.00 - 22.00 WIB', 20000, '[4,28,102,106,107,111]', 'Dilarang rusuh/ribut, dilarang minum minuman keras, jaga ketertiban dan kebersihan', '-5.4708658', '105.2498796', 'https://maps.app.goo.gl/nwqDXMi1REfeMVJi9', '1782551061_19197213906a3f9215aa8ba7.66551901.jpeg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(28, 4, 'Pantai Duta Wisata', 'pantai-duta-wisata', 'Tahun Berdiri: 1995\r\n\r\nDahulu, area Pantai Duta Wisata bukanlah kawasan wisata seperti sekarang. Lokasi ini awalnya merupakan rawa atau lahan basah yang belum dimanfaatkan secara optimal oleh masyarakat sekitar. Seiring berjalannya waktu, lahan rawa tersebut diubah menjadi tempat wisata. Tujuannya agar area yang sebelumnya kurang produktif bisa memberi manfaat ekonomi sekaligus menjadi ruang rekreasi baru bagi masyarakat. Proses awal pembangunan dilakukan dengan pengurukan tanah. Rawa yang ada secara bertahap diuruk menggunakan tanah agar permukaan tanah menjadi lebih padat, rata, dan aman untuk dibangun fasilitas wisata.   Setelah tanah stabil, tahap selanjutnya adalah penanaman pohon-pohon. Penanaman ini bertujuan untuk menghijaukan area, mengurangi hawa panas, dan menciptakan suasana teduh yang nyaman bagi pengunjung. Seiring perubahan bentuk lahan, mulai dibangun berbagai fasilitas dasar seperti pondok-pondok/gazebo serta wahana permainan seperti bebek-bebekan dan ada juga danau untuk bersantai. Pembangunan fasilitas terus dikembangkan agar pengunjung memiliki tempat beristirahat sambil menikmati suasana pantai. Dari proses panjang pengurukan, penanaman, hingga pembangunan fasilitas itulah Pantai Duta Wisata akhirnya terbentuk seperti sekarang. Pantai ini kini menjadi salah satu destinasi wisata di Lampung yang terus berkembang dan dikelola untuk kenyamanan wisatawan.', 'Jl. Laksamana R.E. Martadinata, Kecamatan Teluk Betung Barat, Bandar Lampung', '08.00 - 20.00 WIB', 'Senin - Jum\'at', 20000, '[1,2,3,4,5,6,7,11,15,116]', 'Dilarang berenang ke area yang jauh dan Jaga kebersihan dan keamanan', '-5.4768533', '105.2525653', 'https://maps.app.goo.gl/KrNy7rcsc8eFkVqv6', '1782551061_8822676826a3f9215be3712.61687608.jpeg', '2026-06-23 08:21:11', '2026-06-27 11:00:13'),
(29, 4, 'Pantai Tirtayasa', 'pantai-tirtayasa', 'Tahun Berdiri: 1984\n\nPantai Tirtayasa atau yang lebih dikenal warga Bandar Lampung sebagai Pantai Harnas, sudah lama menjadi salah satu destinasi wisata pantai andalan di Kota Bandar Lampung. Lokasinya yang hanya sekitar 15 menit dari pusat kota membuat pantai ini gampang dijangkau warga sekitar. Nama &quot;Tirtayasa&quot; mulai dikenal luas seiring perkembangan kawasan Teluk Betung Timur. Sementara julukan &quot;Pantai Harnas&quot; muncul karena akses masuk utamanya berada di Gang Harnas, Dusun Way Tataan, Kelurahan Sukamaju. Sejak awal, pantai ini sudah jadi tempat nongkrong favorit warga. Ciri khas Pantai Tirtayasa yang paling mencolok sejak dulu adalah keberadaan panggung. Panggung ini sudah ada dari zaman dulu dan sering dipakai untuk acara hiburan, pentas seni, sampai kegiatan warga sekitar. Pasir putih dan ombaknya yang tenang jadi daya tarik utama pantai ini. Karena ombaknya tidak besar, Pantai Tirtayasa cocok banget buat wisata keluarga, anak-anak berenang, atau sekadar duduk santai sambil lihat sunset. Suasananya lebih tenang dibanding pantai-pantai ramai lain di Lampung. Sampai sekarang Pantai Tirtayasa tetap jadi pilihan warga Bandar Lampung buat liburan singkat tanpa harus keluar kota jauh-jauh.', 'Harnas, Sukamaju, Kecamatan Teluk Betung Timur', '06.00 - 20.00 WIB', 'Setiap Hari', 10000, '[2,4,11]', 'Dilarang berenang ke tempat yang jauh', '-5.4842046', '105.2527274', 'https://maps.app.goo.gl/tpCRYfoyhBEwYMWZ7', '1782551062_5531942646a3f92160348f7.78555917.jpeg', '2026-06-23 08:21:11', '2026-06-27 17:27:50'),
(30, 4, 'Pulau Pasaran', 'pulau-pasaran', 'Tahun Berdiri: Data tidak tersedia\r\n\r\nPulau Pasaran merupakan pulau kecil yang berada di Teluk Lampung dan dikenal sebagai sentra pengolahan ikan teri terbesar di Kota Bandar Lampung. Awalnya pulau ini merupakan kawasan permukiman nelayan yang menggantungkan hidup dari hasil laut. Seiring perkembangan waktu, aktivitas pengolahan ikan teri menjadi daya tarik tersendiri bagi wisatawan yang ingin melihat proses produksi ikan teri secara langsung. Saat ini Pulau Pasaran berkembang menjadi destinasi wisata yang memperkenalkan kehidupan masyarakat pesisir.', 'Kota Karang, Kecamatan Teluk Betung Timur', '24 Jam', 'Setiap Hari', 25000, '[5,6,32]', '1. Menjaga kebersihan lingkungan pulau.\r\n2. Tidak membuang sampah sembarangan.\r\n3. Menghormati aktivitas masyarakat dan nelayan setempat.\r\n4. Tidak merusak fasilitas umum.\r\n5. Menjaga ketertiban dan keamanan selama berkunjung.\r\n6. Mematuhi aturan yang berlaku di kawasan wisata.', '-5.4638889', '105.265', 'https://maps.app.goo.gl/thWDshBZ5s8gmxwb9', '1782551062_18915695806a3f9216100531.89169684.jpg', '2026-06-23 08:21:11', '2026-06-27 10:36:57'),
(31, 5, 'TES', 'tes', 'TES', 'Sumur Putri, Bandar Lampung, Lampung, Sumatra, 35221, Indonesia', '10.00 - 22.00 WIB', 'Setiap Hari', 404404, '[106,107,111,116,117]', 'TES', '-5.430769', '105.228939', 'https://maps.app.goo.gl/thWDshBZ5s8gmxwb9', '1782556987_ec8ccfeee7f6d13d178e.jpg', '2026-06-27 10:43:07', '2026-06-27 11:00:29');
